import { PracticeQuestion } from './types';

// ═══════════════════════════════════════════════════════════════
// NEET UG — 60 Questions (Biology 30, Chemistry 15, Physics 15)
// Chapter-wise, NCERT-based, real exam difficulty
// ═══════════════════════════════════════════════════════════════
export const neetQuestions: PracticeQuestion[] = [
  // BOTANY — Class 11
  { id: 'nb-1', question: 'Which of the following is NOT a characteristic of Kingdom Monera?', options: ['Prokaryotic cells', 'Membrane-bound organelles', 'Cell wall present', 'Binary fission'], answer: 1, explanation: 'Monera (bacteria) are prokaryotic — they lack membrane-bound organelles like mitochondria, ER, and nucleus.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-2', question: 'Transpiration pull theory was proposed by:', options: ['J.C. Bose', 'Dixon and Joly', 'Münch', 'Curtis'], answer: 1, explanation: 'Dixon and Joly (1894) proposed the Cohesion-Tension Theory (transpiration pull) explaining ascent of sap in tall trees.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nb-3', question: 'In C4 plants, the primary CO₂ acceptor is:', options: ['RuBisCO', 'PEP carboxylase', 'PGA', 'OAA'], answer: 1, explanation: 'In C4 plants (like sugarcane, maize), PEP carboxylase fixes CO₂ into OAA in mesophyll cells. RuBisCO works only in bundle sheath cells.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nb-4', question: 'During which phase of the cell cycle does DNA replication occur?', options: ['G1 phase', 'S phase', 'G2 phase', 'M phase'], answer: 1, explanation: 'DNA synthesis/replication occurs during the S (Synthesis) phase of interphase. DNA content doubles from 2n to 4n.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-5', question: 'Kranz anatomy is a characteristic of:', options: ['C3 plants', 'C4 plants', 'CAM plants', 'All plants'], answer: 1, explanation: 'Kranz anatomy (wreath-like arrangement of bundle sheath cells with large chloroplasts) is characteristic of C4 plants.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nb-6', question: 'The enzyme that catalyzes the conversion of pyruvate to acetyl CoA is:', options: ['Pyruvate kinase', 'Pyruvate dehydrogenase', 'Pyruvate carboxylase', 'Phosphofructokinase'], answer: 1, explanation: 'Pyruvate dehydrogenase complex converts pyruvate to acetyl CoA (with release of CO₂ and NADH) in the mitochondrial matrix.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nb-7', question: 'Which phytohormone is known as the "stress hormone"?', options: ['Auxin', 'Gibberellin', 'Abscisic acid', 'Cytokinin'], answer: 2, explanation: 'Abscisic acid (ABA) is called the stress hormone because it helps plants respond to drought, salinity, and cold stress by closing stomata.', subject: 'Biology', difficulty: 'easy' },
  // BOTANY — Class 12
  { id: 'nb-8', question: 'Double fertilization in angiosperms involves fusion of:', options: ['One sperm with egg and another with polar nuclei', 'Two sperms with egg only', 'One sperm with synergids', 'Two eggs with pollen'], answer: 0, explanation: 'Double fertilization: one sperm fuses with egg → zygote (2n), other sperm fuses with two polar nuclei → Primary Endosperm Nucleus (3n).', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-9', question: 'In Mendel\'s dihybrid cross, the phenotypic ratio in F₂ is:', options: ['3:1', '9:3:3:1', '1:2:1', '1:1:1:1'], answer: 1, explanation: 'Mendel\'s dihybrid cross (RrYy × RrYy) gives 9:3:3:1 ratio — 9 round yellow : 3 round green : 3 wrinkled yellow : 1 wrinkled green.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-10', question: 'The process of copying genetic information from one strand of DNA to RNA is called:', options: ['Translation', 'Transcription', 'Replication', 'Transduction'], answer: 1, explanation: 'Transcription is the process of synthesizing mRNA from a DNA template, catalyzed by RNA polymerase.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-11', question: 'Which of the following is NOT a feature of genetic code?', options: ['Triplet', 'Degenerate', 'Ambiguous', 'Universal'], answer: 2, explanation: 'The genetic code is NOT ambiguous — each codon codes for only ONE amino acid. It IS degenerate (multiple codons for same amino acid).', subject: 'Biology', difficulty: 'medium' },
  { id: 'nb-12', question: 'Hardy-Weinberg equilibrium is disturbed by all EXCEPT:', options: ['Gene flow', 'Genetic drift', 'Random mating', 'Natural selection'], answer: 2, explanation: 'Random mating maintains Hardy-Weinberg equilibrium. Gene flow, drift, mutation, selection, and non-random mating disturb it.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nb-13', question: 'Bt toxin kills insects by:', options: ['Blocking nerve signals', 'Creating pores in gut lining', 'Destroying DNA', 'Inhibiting respiration'], answer: 1, explanation: 'Bt toxin (Cry protein) creates pores in the midgut epithelial cells of insects, causing cell swelling, lysis and death.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nb-14', question: 'In an ecosystem, the flow of energy is:', options: ['Bidirectional', 'Unidirectional', 'Cyclic', 'Multidirectional'], answer: 1, explanation: 'Energy flow in an ecosystem is always unidirectional — from sun → producers → consumers. It cannot be recycled (unlike nutrients).', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-15', question: 'The 10% law of energy transfer was given by:', options: ['Odum', 'Lindeman', 'Tansley', 'Haeckel'], answer: 1, explanation: 'Lindeman (1942) proposed the 10% law: only ~10% of energy is transferred from one trophic level to the next.', subject: 'Biology', difficulty: 'medium' },
  // ZOOLOGY — Class 11
  { id: 'nz-1', question: 'The excretory organs of earthworm are:', options: ['Flame cells', 'Malpighian tubules', 'Nephridia', 'Green glands'], answer: 2, explanation: 'Earthworms have nephridia for excretion. Flame cells are in Platyhelminthes. Malpighian tubules in insects. Green glands in crustaceans.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-2', question: 'SA node is called the pacemaker of the heart because it:', options: ['Is the largest node', 'Generates electrical impulses that initiate heartbeat', 'Supplies blood to the heart', 'Controls blood pressure'], answer: 1, explanation: 'SA (Sinoatrial) node in the right atrium generates rhythmic electrical impulses (70-75/min) that initiate each heartbeat.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-3', question: 'Which part of the nephron is impermeable to water?', options: ['PCT', 'DCT', 'Ascending limb of loop of Henle', 'Collecting duct'], answer: 2, explanation: 'The ascending limb of the loop of Henle is impermeable to water but permeable to NaCl — this creates the concentration gradient for counter-current mechanism.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nz-4', question: 'Synapse is the gap between:', options: ['Two bones', 'Two muscle cells', 'Two neurons', 'Neuron and muscle'], answer: 2, explanation: 'A synapse is the junction between two neurons where nerve impulses are transmitted via neurotransmitters (like acetylcholine).', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-5', question: 'Which hormone is secreted by the corpus luteum?', options: ['Estrogen only', 'Progesterone mainly', 'FSH', 'LH'], answer: 1, explanation: 'The corpus luteum (formed from ruptured Graafian follicle after ovulation) primarily secretes progesterone, which maintains the uterine endometrium for pregnancy.', subject: 'Biology', difficulty: 'medium' },
  // ZOOLOGY — Class 12
  { id: 'nz-6', question: 'The process of formation of sperms from spermatogonia is called:', options: ['Oogenesis', 'Spermiogenesis', 'Spermatogenesis', 'Spermiation'], answer: 2, explanation: 'Spermatogenesis is the complete process: spermatogonia → primary spermatocyte → secondary spermatocyte → spermatids → sperms.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-7', question: 'Down syndrome is caused by trisomy of chromosome number:', options: ['18', '21', '13', '23'], answer: 1, explanation: 'Down syndrome (47 chromosomes) is caused by trisomy of chromosome 21 (three copies instead of two). Also called Trisomy 21.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-8', question: 'Which type of immunity is provided by vaccination?', options: ['Natural active immunity', 'Artificial active immunity', 'Natural passive immunity', 'Artificial passive immunity'], answer: 1, explanation: 'Vaccination provides artificial active immunity — antigens are artificially introduced, and the body produces its own antibodies and memory cells.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nz-9', question: 'HIV attacks which type of cells in the human body?', options: ['Red blood cells', 'Helper T cells (CD4+)', 'B cells only', 'Platelets'], answer: 1, explanation: 'HIV primarily attacks helper T cells (CD4+ lymphocytes), destroying them and weakening the immune system, leading to AIDS.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-10', question: 'Cancer cells differ from normal cells because they show:', options: ['Contact inhibition', 'Uncontrolled division', 'Differentiation', 'Apoptosis'], answer: 1, explanation: 'Cancer cells lose contact inhibition and divide uncontrollably, forming tumors. Normal cells stop dividing when they contact other cells.', subject: 'Biology', difficulty: 'easy' },
  // NEET PHYSICS (15 questions)
  { id: 'np-1', question: 'A body is thrown vertically upward. At the highest point:', options: ['Both velocity and acceleration are zero', 'Velocity is zero but acceleration is g', 'Velocity is maximum', 'Acceleration is zero'], answer: 1, explanation: 'At highest point: velocity = 0 (momentarily stops) but acceleration = g (9.8 m/s²) downward always acts due to gravity.', subject: 'Physics', difficulty: 'easy' },
  { id: 'np-2', question: 'Two identical charged spheres are touched and separated. If initial charges are +6μC and -2μC, charge on each after touching:', options: ['+4μC', '+2μC', '+3μC', '-2μC'], answer: 1, explanation: 'When identical spheres touch, total charge distributes equally. Total = +6 + (-2) = +4μC. Each gets +4/2 = +2μC.', subject: 'Physics', difficulty: 'easy' },
  { id: 'np-3', question: 'The equivalent resistance of 2Ω and 3Ω in parallel is:', options: ['5Ω', '1.2Ω', '6Ω', '0.83Ω'], answer: 1, explanation: '1/R = 1/2 + 1/3 = (3+2)/6 = 5/6. So R = 6/5 = 1.2Ω. Parallel resistance is always less than the smallest individual resistance.', subject: 'Physics', difficulty: 'easy' },
  { id: 'np-4', question: 'The focal length of a concave mirror is 10 cm. An object is placed at 15 cm. The image is:', options: ['Virtual and erect', 'Real and inverted, at 30 cm', 'Virtual and magnified', 'At infinity'], answer: 1, explanation: 'Using 1/f = 1/v + 1/u: 1/(-10) = 1/v + 1/(-15). 1/v = -1/10 + 1/15 = (-3+2)/30 = -1/30. v = -30 cm. Real, inverted, magnified.', subject: 'Physics', difficulty: 'medium' },
  { id: 'np-5', question: 'In photoelectric effect, the maximum kinetic energy of photoelectrons depends on:', options: ['Intensity of light', 'Frequency of light', 'Number of photons', 'Area of metal surface'], answer: 1, explanation: 'KEmax = hf - φ (Einstein equation). KE depends on frequency (f) of incident light, NOT intensity. Higher frequency = higher KE.', subject: 'Physics', difficulty: 'medium' },
  { id: 'np-6', question: 'The dimension of Planck\'s constant is same as:', options: ['Energy', 'Angular momentum', 'Linear momentum', 'Force'], answer: 1, explanation: 'Planck constant h has units J·s = kg·m²/s. Angular momentum (L = mvr) also has units kg·m²/s. Same dimensions: [ML²T⁻¹].', subject: 'Physics', difficulty: 'medium' },
  { id: 'np-7', question: 'A transformer has 100 turns in primary and 500 in secondary. If input voltage is 220V, output voltage is:', options: ['44V', '1100V', '880V', '220V'], answer: 1, explanation: 'Vs/Vp = Ns/Np. Vs = 220 × (500/100) = 220 × 5 = 1100V. This is a step-up transformer.', subject: 'Physics', difficulty: 'easy' },
  { id: 'np-8', question: 'The work done in moving a charge of 5C across a potential difference of 12V is:', options: ['60 J', '2.4 J', '17 J', '7 J'], answer: 0, explanation: 'W = qV = 5 × 12 = 60 J. Work done = charge × potential difference.', subject: 'Physics', difficulty: 'easy' },
  { id: 'np-9', question: 'In a pure inductive AC circuit, current lags voltage by:', options: ['0°', '90°', '180°', '45°'], answer: 1, explanation: 'In a pure inductor, current lags behind voltage by exactly 90° (π/2 radians). Mnemonic: ELI (E leads I in inductor L).', subject: 'Physics', difficulty: 'medium' },
  { id: 'np-10', question: 'The binding energy per nucleon is maximum for:', options: ['Hydrogen', 'Uranium-238', 'Iron-56', 'Helium-4'], answer: 2, explanation: 'Iron-56 has the highest binding energy per nucleon (~8.8 MeV). This is why elements lighter than Fe undergo fusion and heavier ones undergo fission.', subject: 'Physics', difficulty: 'medium' },
  // NEET CHEMISTRY (15 questions)
  { id: 'nc-1', question: 'The number of moles of CO₂ that contain 3.011 × 10²³ molecules is:', options: ['0.25', '0.5', '1', '2'], answer: 1, explanation: '1 mole = 6.022 × 10²³. Moles = 3.011 × 10²³ / 6.022 × 10²³ = 0.5 moles.', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'nc-2', question: 'The hybridization of carbon in ethene (C₂H₄) is:', options: ['sp', 'sp²', 'sp³', 'sp³d'], answer: 1, explanation: 'In ethene, each carbon forms 3 sigma bonds (2 C-H + 1 C-C) and 1 pi bond. Three sigma bonds require sp² hybridization (trigonal planar, 120°).', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'nc-3', question: 'Which of the following is the strongest acid?', options: ['HF', 'HCl', 'HBr', 'HI'], answer: 3, explanation: 'Acid strength increases down the group: HF < HCl < HBr < HI. HI is the strongest because the H-I bond is weakest and easiest to break.', subject: 'Chemistry', difficulty: 'medium' },
  { id: 'nc-4', question: 'In SN1 reaction, the rate depends on:', options: ['Both substrate and nucleophile', 'Only substrate concentration', 'Only nucleophile concentration', 'Solvent only'], answer: 1, explanation: 'SN1 is unimolecular — Rate = k[substrate]. The slow step is carbocation formation, which depends only on substrate concentration.', subject: 'Chemistry', difficulty: 'medium' },
  { id: 'nc-5', question: 'The IUPAC name of CH₃-CO-CH₃ is:', options: ['Acetone', 'Propanone', 'Propanal', 'Propanoic acid'], answer: 1, explanation: 'CH₃COCH₃ is a ketone with 3 carbons. IUPAC: propan- (3C) + -one (ketone) = Propanone. Acetone is the common name.', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'nc-6', question: 'Which of the following has the highest lattice energy?', options: ['NaCl', 'NaBr', 'NaI', 'NaF'], answer: 3, explanation: 'Lattice energy ∝ (charge)/(size). NaF has the smallest anion (F⁻), so it has the highest lattice energy among sodium halides.', subject: 'Chemistry', difficulty: 'medium' },
  { id: 'nc-7', question: 'The coordination number of Fe in [Fe(CN)₆]⁴⁻ is:', options: ['2', '4', '6', '8'], answer: 2, explanation: 'Coordination number = number of ligands directly bonded to metal. CN⁻ is a monodentate ligand. 6 CN⁻ ligands → coordination number = 6.', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'nc-8', question: 'Which polymer is a natural polymer?', options: ['PVC', 'Nylon', 'Cellulose', 'Teflon'], answer: 2, explanation: 'Cellulose is a natural polymer of glucose. PVC, Nylon, and Teflon are all synthetic polymers.', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'nc-9', question: 'The element with electronic configuration [Ar] 3d⁵ 4s¹ is:', options: ['Mn', 'Fe', 'Cr', 'V'], answer: 2, explanation: 'Chromium (Cr, Z=24) has [Ar] 3d⁵ 4s¹ (not 3d⁴ 4s²) due to extra stability of half-filled d orbitals.', subject: 'Chemistry', difficulty: 'medium' },
  { id: 'nc-10', question: 'Aspirin is chemically known as:', options: ['Methyl salicylate', 'Acetyl salicylic acid', 'Benzoic acid', 'Phenol'], answer: 1, explanation: 'Aspirin = Acetyl salicylic acid. It is an analgesic (pain reliever) and antipyretic (fever reducer) used widely as a drug.', subject: 'Chemistry', difficulty: 'easy' },
  // ADDITIONAL NEET — Biology High Yield
  { id: 'nb-16', question: 'Which of the following is a vestigial organ in humans?', options: ['Kidney', 'Appendix', 'Liver', 'Heart'], answer: 1, explanation: 'The vermiform appendix is a vestigial organ — reduced in function during evolution. It was useful in herbivorous ancestors for cellulose digestion.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-17', question: 'The structural and functional unit of lungs is:', options: ['Alveolus', 'Bronchus', 'Trachea', 'Larynx'], answer: 0, explanation: 'Alveoli are tiny air sacs where gas exchange occurs. Each lung has ~300 million alveoli, providing a huge surface area (~80 m²).', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-18', question: 'Which vitamin is synthesized by bacteria in the human gut?', options: ['Vitamin A', 'Vitamin C', 'Vitamin D', 'Vitamin K'], answer: 3, explanation: 'Vitamin K is synthesized by gut bacteria (intestinal flora). It is essential for blood clotting (synthesis of prothrombin).', subject: 'Biology', difficulty: 'medium' },
  { id: 'nb-19', question: 'Restriction enzymes are used in genetic engineering to:', options: ['Join DNA fragments', 'Cut DNA at specific sites', 'Copy DNA', 'Translate DNA'], answer: 1, explanation: 'Restriction endonucleases (molecular scissors) cut DNA at specific palindromic recognition sequences. EcoRI cuts at GAATTC.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nb-20', question: 'The greenhouse gas with maximum contribution to global warming is:', options: ['Methane', 'Carbon dioxide', 'Nitrous oxide', 'CFC'], answer: 1, explanation: 'CO₂ contributes ~60% to global warming due to its abundance. Though methane is more potent per molecule, CO₂ is far more abundant.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-11', question: 'Erythropoietin, which stimulates RBC production, is secreted by:', options: ['Liver', 'Kidney', 'Spleen', 'Bone marrow'], answer: 1, explanation: 'Kidneys produce erythropoietin (EPO) in response to low oxygen levels. EPO stimulates red blood cell production in bone marrow.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nz-12', question: 'Turner syndrome has the chromosomal composition:', options: ['44+XXY', '44+XO', '44+XXX', '44+XYY'], answer: 1, explanation: 'Turner syndrome = 45,X (44 autosomes + one X). Females are short, sterile, with webbed neck. Caused by monosomy of X chromosome.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nz-13', question: 'Which immunoglobulin is found in colostrum (first milk)?', options: ['IgG', 'IgA', 'IgM', 'IgE'], answer: 1, explanation: 'IgA is the major immunoglobulin in colostrum and mucosal secretions. It provides passive immunity to newborns through breastfeeding.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nz-14', question: 'Ozone layer is found in which layer of atmosphere?', options: ['Troposphere', 'Stratosphere', 'Mesosphere', 'Thermosphere'], answer: 1, explanation: 'The ozone layer is in the stratosphere (15-35 km altitude). It absorbs harmful UV-B and UV-C radiation from the sun.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-15', question: 'PCR (Polymerase Chain Reaction) was invented by:', options: ['Watson', 'Kary Mullis', 'Sanger', 'Boyer'], answer: 1, explanation: 'Kary Mullis invented PCR in 1983 and won the Nobel Prize in Chemistry (1993). PCR amplifies specific DNA sequences using Taq polymerase.', subject: 'Biology', difficulty: 'medium' },
  // ADDITIONAL NEET — Physics
  { id: 'np-11', question: 'A body of mass 10 kg is at rest. A force of 20 N is applied. Its acceleration is:', options: ['0.5 m/s²', '2 m/s²', '10 m/s²', '200 m/s²'], answer: 1, explanation: 'F = ma. a = F/m = 20/10 = 2 m/s². Newton\'s second law.', subject: 'Physics', difficulty: 'easy' },
  { id: 'np-12', question: 'The angle of incidence equals the angle of reflection. This is the law of:', options: ['Refraction', 'Reflection', 'Diffraction', 'Polarization'], answer: 1, explanation: 'Law of reflection: angle of incidence = angle of reflection. Both angles are measured from the normal to the surface.', subject: 'Physics', difficulty: 'easy' },
  { id: 'np-13', question: 'A wire of resistance R is stretched to double its length. Its new resistance is:', options: ['R', '2R', '4R', 'R/2'], answer: 2, explanation: 'R = ρL/A. When length doubles, area halves (volume constant). New R = ρ(2L)/(A/2) = 4ρL/A = 4R.', subject: 'Physics', difficulty: 'medium' },
  { id: 'np-14', question: 'Which electromagnetic wave has the highest frequency?', options: ['Radio waves', 'Microwaves', 'X-rays', 'Gamma rays'], answer: 3, explanation: 'EM spectrum by increasing frequency: Radio < Micro < IR < Visible < UV < X-ray < Gamma. Gamma rays have the highest frequency and energy.', subject: 'Physics', difficulty: 'easy' },
  { id: 'np-15', question: 'In nuclear fission of U-235, the approximate energy released per fission is:', options: ['2 MeV', '20 MeV', '200 MeV', '2000 MeV'], answer: 2, explanation: 'Each fission of U-235 releases approximately 200 MeV of energy. This energy comes from the mass defect (E=mc²).', subject: 'Physics', difficulty: 'medium' },
  // ADDITIONAL NEET — Chemistry
  { id: 'nc-11', question: 'Which of the following is the most electronegative element?', options: ['Oxygen', 'Chlorine', 'Fluorine', 'Nitrogen'], answer: 2, explanation: 'Fluorine has the highest electronegativity (3.98 on Pauling scale) of all elements due to its small size and high nuclear charge.', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'nc-12', question: 'Glucose on reduction gives:', options: ['Sorbitol', 'Gluconic acid', 'Sucrose', 'Fructose'], answer: 0, explanation: 'Glucose (aldehyde group) on reduction with Na-Hg/H₂O or NaBH₄ gives sorbitol (a sugar alcohol). Oxidation gives gluconic acid.', subject: 'Chemistry', difficulty: 'medium' },
  { id: 'nc-13', question: 'The gas released when baking soda reacts with acid is:', options: ['Oxygen', 'Hydrogen', 'Carbon dioxide', 'Nitrogen'], answer: 2, explanation: 'NaHCO₃ + HCl → NaCl + H₂O + CO₂↑. Baking soda (sodium bicarbonate) releases CO₂ on reaction with any acid.', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'nc-14', question: 'Which among the following is an example of cationic detergent?', options: ['Sodium lauryl sulphate', 'Cetyltrimethylammonium bromide', 'Sodium stearate', 'Sodium dodecylbenzenesulphonate'], answer: 1, explanation: 'CTAB (Cetyltrimethylammonium bromide) is a cationic detergent — the cation has a long hydrocarbon chain. Used as antiseptic.', subject: 'Chemistry', difficulty: 'hard' },
  { id: 'nc-15', question: 'The number of sigma and pi bonds in ethyne (C₂H₂) is:', options: ['3σ, 2π', '2σ, 3π', '5σ, 0π', '2σ, 2π'], answer: 0, explanation: 'Ethyne: H-C≡C-H. Triple bond = 1σ + 2π. Two C-H bonds = 2σ. Total: 3σ + 2π bonds.', subject: 'Chemistry', difficulty: 'medium' },
  // ═══ NEET BATCH 3 — High-yield chapters ═══
  // Genetics & Molecular Biology (most asked in NEET)
  { id: 'nb-21', question: 'A cross between Tt × Tt gives what ratio of tall to dwarf plants?', options: ['1:1', '2:1', '3:1', '4:0'], answer: 2, explanation: 'Tt × Tt: TT + 2Tt + tt. Phenotype: 3 Tall (TT, Tt, Tt) : 1 Dwarf (tt) = 3:1 ratio.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-22', question: 'If both parents are carriers for sickle cell anemia (Aa), probability of affected child is:', options: ['0%', '25%', '50%', '75%'], answer: 1, explanation: 'Aa × Aa → 1 AA : 2 Aa : 1 aa. Only aa is affected = 1/4 = 25%. Sickle cell is autosomal recessive.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nb-23', question: 'The start codon in mRNA is:', options: ['UAA', 'UAG', 'AUG', 'UGA'], answer: 2, explanation: 'AUG is the start codon — codes for methionine. It initiates translation. UAA, UAG, UGA are stop codons.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-24', question: 'Which RNA carries amino acids to the ribosome during translation?', options: ['mRNA', 'tRNA', 'rRNA', 'snRNA'], answer: 1, explanation: 'tRNA (transfer RNA) carries amino acids to the ribosome. It has an anticodon loop that matches the mRNA codon and an amino acid attachment site.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-25', question: 'Crossing over occurs during which stage of meiosis?', options: ['Leptotene', 'Zygotene', 'Pachytene', 'Diplotene'], answer: 2, explanation: 'Crossing over (recombination) occurs during pachytene of meiosis I prophase. Bivalents exchange genetic material at chiasmata.', subject: 'Biology', difficulty: 'medium' },
  // Ecology (high weightage)
  { id: 'nb-26', question: 'The pyramid of energy in an ecosystem is always:', options: ['Upright', 'Inverted', 'Spindle-shaped', 'Varies'], answer: 0, explanation: 'The pyramid of energy is ALWAYS upright because energy decreases at each trophic level (only 10% is transferred). Unlike biomass/numbers which can be inverted.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nb-27', question: 'An example of ex situ conservation is:', options: ['National Park', 'Wildlife Sanctuary', 'Botanical Garden', 'Biosphere Reserve'], answer: 2, explanation: 'Ex situ = outside natural habitat. Botanical gardens, zoos, seed banks. In situ = in natural habitat: national parks, sanctuaries, biosphere reserves.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-28', question: 'The relationship between clownfish and sea anemone is:', options: ['Parasitism', 'Commensalism', 'Mutualism', 'Competition'], answer: 2, explanation: 'Mutualism: clownfish gets protection from predators, sea anemone gets food scraps and cleaning from clownfish. Both benefit.', subject: 'Biology', difficulty: 'easy' },
  // Human Physiology (most asked in NEET)
  { id: 'nz-16', question: 'The hormone responsible for "fight or flight" response is:', options: ['Insulin', 'Thyroxine', 'Adrenaline', 'Melatonin'], answer: 2, explanation: 'Adrenaline (epinephrine) from adrenal medulla triggers the fight-or-flight response: increased heart rate, blood pressure, glucose levels.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-17', question: 'Insulin is secreted by which cells of the pancreas?', options: ['Alpha cells', 'Beta cells', 'Delta cells', 'PP cells'], answer: 1, explanation: 'Beta cells of islets of Langerhans secrete insulin (lowers blood glucose). Alpha cells secrete glucagon (raises blood glucose).', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-18', question: 'The total volume of air that can be inspired after a normal expiration is called:', options: ['Tidal volume', 'Vital capacity', 'Inspiratory capacity', 'Total lung capacity'], answer: 2, explanation: 'Inspiratory capacity (IC) = Tidal volume + Inspiratory reserve volume. It is the maximum air that can be inspired after normal expiration.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nz-19', question: 'Blood group AB is called universal recipient because:', options: ['It has no antigens', 'It has both A and B antigens but no antibodies', 'It has all antibodies', 'It produces no clotting factors'], answer: 1, explanation: 'AB blood has both A and B antigens on RBCs and NO anti-A or anti-B antibodies in plasma. So it can receive blood from any group.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-20', question: 'The number of cranial nerves in humans is:', options: ['10 pairs', '12 pairs', '21 pairs', '31 pairs'], answer: 1, explanation: '12 pairs of cranial nerves emerge from the brain. 31 pairs of spinal nerves emerge from the spinal cord. Total = 43 pairs.', subject: 'Biology', difficulty: 'easy' },
  // NEET Physics — Optics & Modern Physics
  { id: 'np-16', question: 'The power of a lens with focal length 25 cm is:', options: ['0.25 D', '2.5 D', '4 D', '25 D'], answer: 2, explanation: 'P = 1/f (in meters). f = 25 cm = 0.25 m. P = 1/0.25 = 4 Diopters.', subject: 'Physics', difficulty: 'easy' },
  { id: 'np-17', question: 'In Bohr model, the radius of nth orbit is proportional to:', options: ['n', 'n²', '1/n', '1/n²'], answer: 1, explanation: 'Bohr radius: rₙ = n² × r₁ (where r₁ = 0.529 Å). Radius is proportional to n². Energy is proportional to -1/n².', subject: 'Physics', difficulty: 'medium' },
  { id: 'np-18', question: 'The unit of radioactivity is:', options: ['Gray', 'Sievert', 'Becquerel', 'Roentgen'], answer: 2, explanation: 'SI unit of radioactivity (rate of decay) is Becquerel (Bq) = 1 disintegration/second. Gray = absorbed dose. Sievert = equivalent dose.', subject: 'Physics', difficulty: 'easy' },
  // NEET Chemistry — Organic
  { id: 'nc-16', question: 'Markovnikov\'s rule is about:', options: ['Addition to symmetric alkenes', 'HX addition: H goes to C with more H', 'Elimination reactions', 'Substitution reactions'], answer: 1, explanation: 'Markovnikov rule: In HX addition to unsymmetrical alkene, H adds to the carbon with MORE hydrogen atoms. Anti-Markovnikov gives opposite.', subject: 'Chemistry', difficulty: 'medium' },
  { id: 'nc-17', question: 'Tollen\'s test is positive for:', options: ['Ketones', 'Aldehydes', 'Alcohols', 'Ethers'], answer: 1, explanation: 'Tollen\'s test (silver mirror test) is positive for aldehydes. Ag⁺ is reduced to Ag metal (silver mirror) by the aldehyde group. Ketones do NOT give this test.', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'nc-18', question: 'Which amino acid is non-essential?', options: ['Valine', 'Leucine', 'Alanine', 'Tryptophan'], answer: 2, explanation: 'Alanine is non-essential (body can synthesize it). Valine, Leucine, and Tryptophan are essential amino acids (must come from diet).', subject: 'Chemistry', difficulty: 'medium' },
  // ═══ NEET BATCH 4 — More high-yield chapters ═══
  { id: 'nb-29', question: 'The number of chromosomes in a human gamete is:', options: ['46', '23', '22', '44'], answer: 1, explanation: 'Gametes (sperm/egg) are haploid with 23 chromosomes (22 autosomes + 1 sex chromosome). Somatic cells have 46 (diploid).', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-30', question: 'Which is NOT a sexually transmitted disease?', options: ['Syphilis', 'Gonorrhoea', 'AIDS', 'Typhoid'], answer: 3, explanation: 'Typhoid is caused by Salmonella typhi through contaminated food/water. Syphilis (Treponema), Gonorrhoea (Neisseria), AIDS (HIV) are all STDs.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-31', question: 'Golden rice is enriched with:', options: ['Vitamin A (beta-carotene)', 'Vitamin C', 'Iron', 'Protein'], answer: 0, explanation: 'Golden rice was genetically engineered to produce beta-carotene (precursor of Vitamin A) to combat Vitamin A deficiency in developing countries.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nb-32', question: 'Which vector is used in genetic engineering to transfer genes into plants?', options: ['Bacteriophage', 'Agrobacterium tumefaciens', 'E. coli', 'Retrovirus'], answer: 1, explanation: 'Agrobacterium tumefaciens (with Ti plasmid) is nature\'s genetic engineer — it naturally transfers T-DNA into plant cells. Used extensively in plant biotechnology.', subject: 'Biology', difficulty: 'medium' },
  { id: 'nz-21', question: 'Pepsin works optimally at pH:', options: ['2', '7', '9', '5'], answer: 0, explanation: 'Pepsin is a protease enzyme in the stomach that works best at pH 1.5-2 (highly acidic). HCl in gastric juice creates this acidic environment.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-22', question: 'Which is the longest cell in the human body?', options: ['Red blood cell', 'Neuron', 'Muscle cell', 'Ovum'], answer: 1, explanation: 'Neurons (nerve cells) can be up to 1 meter long (e.g., sciatic nerve). They are the longest cells. Ovum is the largest cell by volume.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-23', question: 'Bile is produced by the _____ and stored in the _____:', options: ['Liver; Gallbladder', 'Gallbladder; Liver', 'Pancreas; Liver', 'Stomach; Duodenum'], answer: 0, explanation: 'Bile is produced by the liver (hepatocytes), stored and concentrated in the gallbladder, and released into the duodenum to emulsify fats.', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-24', question: 'The oxygen-carrying pigment in blood is:', options: ['Myoglobin', 'Hemoglobin', 'Hemocyanin', 'Chlorophyll'], answer: 1, explanation: 'Hemoglobin (Hb) in RBCs carries oxygen. Each Hb molecule has 4 heme groups with iron (Fe²⁺) that bind O₂. Hemocyanin is in invertebrates (copper-based).', subject: 'Biology', difficulty: 'easy' },
  { id: 'nz-25', question: 'GFR (Glomerular Filtration Rate) in a healthy person is approximately:', options: ['25 mL/min', '125 mL/min', '250 mL/min', '500 mL/min'], answer: 1, explanation: 'Normal GFR is ~125 mL/min or 180 litres/day. Of this, 99% is reabsorbed, and only ~1.5 litres is excreted as urine daily.', subject: 'Biology', difficulty: 'medium' },
  { id: 'np-19', question: 'The colour of light with maximum wavelength in the visible spectrum is:', options: ['Violet', 'Blue', 'Green', 'Red'], answer: 3, explanation: 'Red light has the maximum wavelength (~700 nm) and minimum frequency in the visible spectrum. VIBGYOR: Violet has the least wavelength (~400 nm).', subject: 'Physics', difficulty: 'easy' },
  { id: 'np-20', question: 'If two identical charges are separated by distance d, the force between them is F. If distance is halved, force becomes:', options: ['F/2', '2F', '4F', 'F/4'], answer: 2, explanation: 'Coulomb law: F ∝ 1/d². If d becomes d/2: F\' = F × (d/(d/2))² = F × 4 = 4F. Force quadruples when distance halves.', subject: 'Physics', difficulty: 'medium' },
  { id: 'nc-19', question: 'The process of conversion of glucose to pyruvate is called:', options: ['Krebs cycle', 'Glycolysis', 'Fermentation', 'Gluconeogenesis'], answer: 1, explanation: 'Glycolysis (Embden-Meyerhof pathway) converts 1 glucose (6C) to 2 pyruvate (3C) in the cytoplasm, yielding 2 ATP and 2 NADH.', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'nc-20', question: 'Which of the following is a biodegradable polymer?', options: ['PVC', 'Polythene', 'PHBV', 'Teflon'], answer: 2, explanation: 'PHBV (Poly-β-hydroxybutyrate-co-β-hydroxyvalerate) is a biodegradable polymer. PVC, Polythene, and Teflon are non-biodegradable synthetic polymers.', subject: 'Chemistry', difficulty: 'medium' },
];

// ═══════════════════════════════════════════════════════════════
// JEE MAIN — 50 Questions (Physics 17, Chemistry 16, Maths 17)
// ═══════════════════════════════════════════════════════════════
export const jeeMainQuestions: PracticeQuestion[] = [
  // JEE PHYSICS
  { id: 'jp-1', question: 'A ball is thrown vertically upward with velocity 20 m/s. The maximum height reached is (g = 10 m/s²):', options: ['10 m', '20 m', '30 m', '40 m'], answer: 1, explanation: 'Using v² = u² - 2gh. At max height v=0: h = u²/2g = (20)²/(2×10) = 400/20 = 20 m.', subject: 'Physics', difficulty: 'easy' },
  { id: 'jp-2', question: 'A block of mass 5 kg on a rough surface (μ=0.4) needs a horizontal force to start moving (g=10):', options: ['10N', '20N', '30N', '40N'], answer: 1, explanation: 'F = μmg = 0.4 × 5 × 10 = 20N. This is the minimum force to overcome static friction.', subject: 'Physics', difficulty: 'easy' },
  { id: 'jp-3', question: 'Two capacitors 3μF and 6μF are connected in series. The equivalent capacitance is:', options: ['9μF', '2μF', '4.5μF', '1μF'], answer: 1, explanation: '1/C = 1/3 + 1/6 = (2+1)/6 = 3/6 = 1/2. C = 2μF. Series capacitance is always less than the smallest.', subject: 'Physics', difficulty: 'easy' },
  { id: 'jp-4', question: 'The de Broglie wavelength of an electron accelerated through potential V is:', options: ['√(2meV)/h', 'h/√(2meV)', '2meV/h', 'h²/2meV'], answer: 1, explanation: 'λ = h/p = h/√(2mKE) = h/√(2meV). Where KE = eV for an electron accelerated through potential V.', subject: 'Physics', difficulty: 'medium' },
  { id: 'jp-5', question: 'In Young\'s double slit experiment, if slit width is halved, fringe width:', options: ['Halved', 'Doubled', 'Unchanged', 'Quadrupled'], answer: 1, explanation: 'Fringe width β = λD/d. If d (slit separation) is halved, β doubles. Fringe width is inversely proportional to slit separation.', subject: 'Physics', difficulty: 'medium' },
  { id: 'jp-6', question: 'The moment of inertia of a solid sphere about its diameter is:', options: ['MR²', '2/5 MR²', '2/3 MR²', '1/2 MR²'], answer: 1, explanation: 'Moment of inertia of solid sphere about diameter = 2/5 MR². This is a standard result derived by integration.', subject: 'Physics', difficulty: 'medium' },
  { id: 'jp-7', question: 'The escape velocity from Earth is approximately:', options: ['7.9 km/s', '11.2 km/s', '15.4 km/s', '3.2 km/s'], answer: 1, explanation: 'Escape velocity Ve = √(2gR) = √(2 × 9.8 × 6400000) ≈ 11.2 km/s. Independent of mass of the object.', subject: 'Physics', difficulty: 'easy' },
  { id: 'jp-8', question: 'In an RC circuit, the time constant τ is:', options: ['R/C', 'RC', 'R+C', '1/RC'], answer: 1, explanation: 'Time constant τ = RC. It represents the time for capacitor to charge to 63.2% of maximum value (or discharge to 36.8%).', subject: 'Physics', difficulty: 'medium' },
  // JEE CHEMISTRY
  { id: 'jc-1', question: 'The number of moles in 36 g of water (H₂O, MW=18) is:', options: ['1', '2', '3', '4'], answer: 1, explanation: 'Moles = mass/MW = 36/18 = 2 moles.', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'jc-2', question: 'For an exothermic reaction, ΔH is:', options: ['Positive', 'Negative', 'Zero', 'Cannot be determined'], answer: 1, explanation: 'Exothermic reactions release heat → products have lower energy than reactants → ΔH < 0 (negative).', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'jc-3', question: 'The oxidation state of Mn in KMnO₄ is:', options: ['+2', '+4', '+5', '+7'], answer: 3, explanation: 'In KMnO₄: K is +1, each O is -2. +1 + x + 4(-2) = 0. x - 7 = 0. x = +7.', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'jc-4', question: 'The pH of 0.01 M HCl solution is:', options: ['1', '2', '3', '0.01'], answer: 1, explanation: 'HCl is a strong acid, fully dissociates. [H⁺] = 0.01 = 10⁻². pH = -log(10⁻²) = 2.', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'jc-5', question: 'Grignard reagent is:', options: ['RMgBr', 'RLi', 'RZnCl', 'RNa'], answer: 0, explanation: 'Grignard reagent = RMgX (where X = halide). e.g., CH₃MgBr. Used extensively in organic synthesis for C-C bond formation.', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'jc-6', question: 'Which has maximum number of unpaired electrons?', options: ['Fe²⁺', 'Fe³⁺', 'Mn²⁺', 'Cu²⁺'], answer: 2, explanation: 'Mn²⁺ = [Ar]3d⁵ has 5 unpaired electrons (maximum). Fe³⁺ also has 5, but Mn²⁺ and Fe³⁺ tie. Fe²⁺ has 4, Cu²⁺ has 1.', subject: 'Chemistry', difficulty: 'medium' },
  { id: 'jc-7', question: 'Lucas reagent is used to distinguish between:', options: ['Alkenes and alkynes', '1°, 2°, and 3° alcohols', 'Aldehydes and ketones', 'Acids and esters'], answer: 1, explanation: 'Lucas reagent (conc. HCl + ZnCl₂) distinguishes alcohols: 3° reacts immediately (turbid), 2° in 5 min, 1° very slowly/no reaction.', subject: 'Chemistry', difficulty: 'medium' },
  { id: 'jc-8', question: 'The rate constant of a first-order reaction has units:', options: ['mol/L/s', 's⁻¹', 'L/mol/s', 'mol²/L²/s'], answer: 1, explanation: 'For first-order: Rate = k[A]. k = Rate/[A] = (mol/L/s)/(mol/L) = s⁻¹. The unit is always time inverse for first order.', subject: 'Chemistry', difficulty: 'medium' },
  // JEE MATHS
  { id: 'jm-1', question: 'If sin θ = 3/5, then cos θ is:', options: ['4/5', '3/4', '5/3', '5/4'], answer: 0, explanation: 'sin²θ + cos²θ = 1. cos²θ = 1 - 9/25 = 16/25. cos θ = 4/5 (in first quadrant).', subject: 'Maths', difficulty: 'easy' },
  { id: 'jm-2', question: 'The derivative of x³ with respect to x is:', options: ['x²', '3x²', '3x³', 'x³/3'], answer: 1, explanation: 'Power rule: d/dx(xⁿ) = nxⁿ⁻¹. d/dx(x³) = 3x².', subject: 'Maths', difficulty: 'easy' },
  { id: 'jm-3', question: '∫₀¹ 2x dx equals:', options: ['0', '1', '2', '½'], answer: 1, explanation: '∫₀¹ 2x dx = [x²]₀¹ = 1² - 0² = 1.', subject: 'Maths', difficulty: 'easy' },
  { id: 'jm-4', question: 'The number of ways to arrange 5 books on a shelf is:', options: ['25', '120', '60', '10'], answer: 1, explanation: '5! = 5 × 4 × 3 × 2 × 1 = 120. Arrangement of n distinct items = n!', subject: 'Maths', difficulty: 'easy' },
  { id: 'jm-5', question: 'In the expansion of (1+x)ⁿ, the coefficient of x² is:', options: ['n', 'n(n-1)/2', 'n²', '2n'], answer: 1, explanation: 'By binomial theorem: C(n,2) = n!/(2!(n-2)!) = n(n-1)/2.', subject: 'Maths', difficulty: 'medium' },
  { id: 'jm-6', question: 'The equation of a circle with centre (2,3) and radius 5 is:', options: ['(x-2)²+(y-3)²=25', '(x+2)²+(y+3)²=25', '(x-2)²+(y-3)²=5', 'x²+y²=25'], answer: 0, explanation: 'Standard form: (x-h)² + (y-k)² = r². Centre (2,3), r=5: (x-2)² + (y-3)² = 25.', subject: 'Maths', difficulty: 'easy' },
  { id: 'jm-7', question: 'The rank of the matrix [[1,2],[2,4]] is:', options: ['0', '1', '2', '3'], answer: 1, explanation: 'Row 2 = 2 × Row 1, so rows are linearly dependent. Rank = number of linearly independent rows = 1.', subject: 'Maths', difficulty: 'medium' },
  { id: 'jm-8', question: 'If a⃗ = 2î+3ĵ and b⃗ = î-ĵ, then a⃗·b⃗ is:', options: ['5', '-1', '1', '7'], answer: 1, explanation: 'a⃗·b⃗ = (2)(1) + (3)(-1) = 2 - 3 = -1. Dot product = sum of products of corresponding components.', subject: 'Maths', difficulty: 'easy' },
  { id: 'jm-9', question: 'The probability of getting exactly 2 heads in 3 tosses of a fair coin:', options: ['1/8', '3/8', '1/2', '1/4'], answer: 1, explanation: 'P = C(3,2) × (1/2)² × (1/2)¹ = 3 × 1/4 × 1/2 = 3/8. Using binomial probability.', subject: 'Maths', difficulty: 'medium' },
  // ADDITIONAL JEE — Physics
  { id: 'jp-9', question: 'A projectile is fired at 45° with horizontal. Its range is maximum when angle is:', options: ['30°', '45°', '60°', '90°'], answer: 1, explanation: 'Range R = u²sin2θ/g. R is maximum when sin2θ = 1, i.e., 2θ = 90°, θ = 45°.', subject: 'Physics', difficulty: 'easy' },
  { id: 'jp-10', question: 'The energy stored in a capacitor of capacitance C charged to voltage V is:', options: ['CV', 'CV²', '½CV²', '2CV²'], answer: 2, explanation: 'Energy = ½CV² = ½QV = Q²/2C. All three forms are equivalent.', subject: 'Physics', difficulty: 'easy' },
  { id: 'jp-11', question: 'A convex lens of focal length 20 cm produces a real image at 60 cm from lens. Object distance is:', options: ['20 cm', '30 cm', '40 cm', '60 cm'], answer: 1, explanation: '1/f = 1/v - 1/u. 1/20 = 1/60 - 1/u. 1/u = 1/60 - 1/20 = (1-3)/60 = -2/60 = -1/30. u = -30 cm.', subject: 'Physics', difficulty: 'medium' },
  { id: 'jp-12', question: 'The dimension of angular velocity is:', options: ['[T⁻¹]', '[LT⁻¹]', '[ML²T⁻¹]', '[MLT⁻²]'], answer: 0, explanation: 'Angular velocity ω = θ/t. θ is dimensionless (radian). So ω has dimension [T⁻¹].', subject: 'Physics', difficulty: 'easy' },
  // ADDITIONAL JEE — Chemistry  
  { id: 'jc-9', question: 'The hybridization of nitrogen in NH₃ is:', options: ['sp', 'sp²', 'sp³', 'sp³d'], answer: 2, explanation: 'NH₃: N has 3 bond pairs + 1 lone pair = 4 electron pairs → sp³ hybridization. Shape is trigonal pyramidal (not tetrahedral due to lone pair).', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'jc-10', question: 'Which of the following is the correct order of acidic strength?', options: ['HI > HBr > HCl > HF', 'HF > HCl > HBr > HI', 'HCl > HF > HBr > HI', 'HBr > HI > HF > HCl'], answer: 0, explanation: 'Acid strength increases with decreasing bond energy: H-F (568) > H-Cl (431) > H-Br (366) > H-I (298 kJ/mol). Weaker bond = stronger acid.', subject: 'Chemistry', difficulty: 'medium' },
  { id: 'jc-11', question: 'The number of lone pairs on the central atom in H₂O is:', options: ['0', '1', '2', '3'], answer: 2, explanation: 'Oxygen in H₂O: 6 valence electrons - 2 bonding = 4 non-bonding = 2 lone pairs. This gives water its bent shape (104.5°).', subject: 'Chemistry', difficulty: 'easy' },
  { id: 'jc-12', question: 'Le Chatelier principle states that if a system at equilibrium is disturbed, it will:', options: ['Stop reacting', 'Shift to counteract the disturbance', 'Shift to increase the disturbance', 'Remain unchanged'], answer: 1, explanation: 'Le Chatelier principle: a system at equilibrium shifts in the direction that opposes the applied change (temperature, pressure, concentration).', subject: 'Chemistry', difficulty: 'easy' },
  // ADDITIONAL JEE — Maths
  { id: 'jm-10', question: 'The equation of a line with slope 3 passing through (1,2) is:', options: ['y = 3x - 1', 'y = 3x + 1', 'y = 3x - 4', 'y = 3x + 2'], answer: 0, explanation: 'y - y₁ = m(x - x₁). y - 2 = 3(x - 1). y = 3x - 3 + 2 = 3x - 1.', subject: 'Maths', difficulty: 'easy' },
  { id: 'jm-11', question: 'The value of sin 30° + cos 60° is:', options: ['0', '1/2', '1', '√3/2'], answer: 2, explanation: 'sin 30° = 1/2, cos 60° = 1/2. Sum = 1/2 + 1/2 = 1.', subject: 'Maths', difficulty: 'easy' },
  { id: 'jm-12', question: 'If |a⃗| = 3 and |b⃗| = 4, and a⃗ ⊥ b⃗, then |a⃗ + b⃗| is:', options: ['1', '5', '7', '12'], answer: 1, explanation: 'When vectors are perpendicular: |a+b|² = |a|² + |b|² = 9 + 16 = 25. |a+b| = 5. (Pythagorean theorem for vectors).', subject: 'Maths', difficulty: 'medium' },
  // ═══ JEE BATCH 3 ═══
  { id: 'jp-13', question: 'A ball is dropped from height h. Time to reach ground is:', options: ['√(h/g)', '√(2h/g)', '√(h/2g)', '2√(h/g)'], answer: 1, explanation: 'h = ½gt². t² = 2h/g. t = √(2h/g). Using s = ut + ½at² with u=0.', subject: 'Physics', difficulty: 'easy' },
  { id: 'jp-14', question: 'The torque required to produce angular acceleration α in a body of moment of inertia I is:', options: ['Iα', 'I/α', 'α/I', 'I²α'], answer: 0, explanation: 'τ = Iα. This is the rotational analog of F = ma. Torque = Moment of inertia × Angular acceleration.', subject: 'Physics', difficulty: 'easy' },
  { id: 'jp-15', question: 'Gauss\'s law relates electric flux through a closed surface to:', options: ['Total charge inside', 'Total charge outside', 'Electric field at surface', 'Magnetic field'], answer: 0, explanation: 'Gauss law: ∮E⃗·dA⃗ = q_enclosed/ε₀. Electric flux through closed surface = charge enclosed / permittivity of free space.', subject: 'Physics', difficulty: 'medium' },
  { id: 'jp-16', question: 'In a series LCR circuit at resonance, impedance equals:', options: ['√(R²+(XL-XC)²)', 'R only', 'XL only', 'XC only'], answer: 1, explanation: 'At resonance: XL = XC, they cancel out. Z = √(R² + (XL-XC)²) = √(R² + 0) = R. Current is maximum at resonance.', subject: 'Physics', difficulty: 'medium' },
  { id: 'jc-13', question: 'The Wurtz reaction is used to prepare:', options: ['Alkenes', 'Higher alkanes', 'Alcohols', 'Aldehydes'], answer: 1, explanation: 'Wurtz reaction: 2RX + 2Na → R-R + 2NaX. Two alkyl halides coupled with sodium to form a higher alkane (with double the carbons).', subject: 'Chemistry', difficulty: 'medium' },
  { id: 'jc-14', question: 'For an endothermic reaction at equilibrium, increasing temperature will:', options: ['Shift left', 'Shift right (forward)', 'No effect', 'Reaction stops'], answer: 1, explanation: 'Le Chatelier: increasing temperature favors the endothermic direction. For endothermic reaction, forward shift occurs → more products.', subject: 'Chemistry', difficulty: 'medium' },
  { id: 'jc-15', question: 'The order of a reaction is determined by:', options: ['Balanced equation coefficients', 'Experimental rate law', 'Molecularity', 'Temperature'], answer: 1, explanation: 'Order of reaction can ONLY be determined experimentally from the rate law. It cannot be predicted from the balanced equation (unlike molecularity).', subject: 'Chemistry', difficulty: 'medium' },
  { id: 'jm-13', question: 'The value of lim(x→0) sin(x)/x is:', options: ['0', '1', '∞', 'Does not exist'], answer: 1, explanation: 'This is a standard limit: lim(x→0) sin(x)/x = 1. It can be proved using the squeeze theorem or L\'Hôpital\'s rule.', subject: 'Maths', difficulty: 'easy' },
  { id: 'jm-14', question: 'The area of a triangle with vertices (0,0), (4,0), (0,3) is:', options: ['6', '7', '12', '24'], answer: 0, explanation: 'Area = ½|x₁(y₂-y₃) + x₂(y₃-y₁) + x₃(y₁-y₂)| = ½|0 + 4(3-0) + 0| = ½ × 12 = 6. Or simply ½ × base × height = ½ × 4 × 3 = 6.', subject: 'Maths', difficulty: 'easy' },
  { id: 'jm-15', question: 'The general solution of dy/dx = y/x is:', options: ['y = cx', 'y = cx²', 'y = c/x', 'y = c√x'], answer: 0, explanation: 'dy/y = dx/x. Integrating: ln|y| = ln|x| + C₁. y = cx (where c = e^C₁). This is a family of lines through the origin.', subject: 'Maths', difficulty: 'medium' },
];

