// ═══ CA FOUNDATION — 15 Questions ═══
export const caFoundationQuestions: PracticeQuestion[] = [
  { id: 'ca-a1', question: 'Accounting is based on:', options: ['Single Entry System', 'Double Entry System', 'Triple Entry System', 'No specific system'], answer: 1, explanation: 'Modern accounting follows the Double Entry System where every transaction has two aspects — debit and credit — always equal.', subject: 'Accounting', difficulty: 'easy' },
  { id: 'ca-a2', question: 'The accounting equation is:', options: ['Assets = Liabilities + Capital', 'Assets = Capital - Liabilities', 'Capital = Assets + Liabilities', 'Liabilities = Assets + Capital'], answer: 0, explanation: 'Assets = Liabilities + Capital (Owner\'s Equity). This is the foundation of the balance sheet.', subject: 'Accounting', difficulty: 'easy' },
  { id: 'ca-a3', question: 'Depreciation is charged on:', options: ['Current assets', 'Fixed assets', 'Investments', 'Cash'], answer: 1, explanation: 'Depreciation is the systematic allocation of the cost of a fixed (tangible) asset over its useful life. Current assets are not depreciated.', subject: 'Accounting', difficulty: 'easy' },
  { id: 'ca-a4', question: 'Going Concern concept assumes:', options: ['Business will close soon', 'Business will continue indefinitely', 'Business will make profit', 'Business has unlimited funds'], answer: 1, explanation: 'Going Concern assumes the business will continue operating for the foreseeable future. This affects how assets are valued (cost vs liquidation value).', subject: 'Accounting', difficulty: 'easy' },
  { id: 'ca-l1', question: 'The Indian Contract Act was enacted in:', options: ['1860', '1872', '1882', '1930'], answer: 1, explanation: 'The Indian Contract Act, 1872 governs all contracts in India. It defines offer, acceptance, consideration, and void/voidable agreements.', subject: 'Law', difficulty: 'easy' },
  { id: 'ca-l2', question: 'A contract without consideration is:', options: ['Valid', 'Void', 'Voidable', 'Illegal'], answer: 1, explanation: 'Under Section 25 of Indian Contract Act, an agreement without consideration is void, except for gifts, past services, or promises to pay debts barred by limitation.', subject: 'Law', difficulty: 'medium' },
  { id: 'ca-l3', question: 'A minor\'s agreement is:', options: ['Valid', 'Void ab initio', 'Voidable', 'Enforceable'], answer: 1, explanation: 'A minor (person under 18) cannot enter into a contract. Any agreement with a minor is void ab initio (void from the beginning) — Mohiri Bibi v. Dharmodas Ghose.', subject: 'Law', difficulty: 'medium' },
  { id: 'ca-m1', question: 'Simple interest on ₹10,000 at 10% for 2 years is:', options: ['₹1,000', '₹2,000', '₹2,100', '₹10,000'], answer: 1, explanation: 'SI = PRT/100 = 10000 × 10 × 2 / 100 = ₹2,000. Simple interest is calculated only on the principal amount.', subject: 'Maths', difficulty: 'easy' },
  { id: 'ca-m2', question: 'Compound interest on ₹1,000 at 10% for 2 years is:', options: ['₹200', '₹210', '₹220', '₹100'], answer: 1, explanation: 'CI = P(1+r/100)ⁿ - P = 1000(1.1)² - 1000 = 1210 - 1000 = ₹210. Year 1: ₹100, Year 2: ₹110 (interest on interest).', subject: 'Maths', difficulty: 'easy' },
  { id: 'ca-m3', question: 'The mean of 2, 4, 6, 8, 10 is:', options: ['5', '6', '7', '8'], answer: 1, explanation: 'Mean = Sum/Count = (2+4+6+8+10)/5 = 30/5 = 6.', subject: 'Maths', difficulty: 'easy' },
  { id: 'ca-e1', question: 'GDP stands for:', options: ['Gross Domestic Product', 'General Development Plan', 'Growth and Development Policy', 'Grand Domestic Price'], answer: 0, explanation: 'GDP = Gross Domestic Product — the total value of all goods and services produced within a country\'s borders in a year.', subject: 'Economics', difficulty: 'easy' },
  { id: 'ca-e2', question: 'Inflation means:', options: ['Decrease in prices', 'Sustained increase in general price level', 'Increase in production', 'Decrease in money supply'], answer: 1, explanation: 'Inflation is a sustained increase in the general price level of goods and services, reducing the purchasing power of money.', subject: 'Economics', difficulty: 'easy' },
  { id: 'ca-e3', question: 'The law of demand states that when price increases:', options: ['Demand increases', 'Demand decreases', 'Demand stays same', 'Supply increases'], answer: 1, explanation: 'Law of Demand: Price and quantity demanded have an inverse relationship. When price rises, demand falls (ceteris paribus).', subject: 'Economics', difficulty: 'easy' },
  { id: 'ca-e4', question: 'RBI stands for:', options: ['Reserve Board of India', 'Reserve Bank of India', 'Regulatory Bank of India', 'Revenue Bank of India'], answer: 1, explanation: 'Reserve Bank of India (RBI) is India\'s central bank, established in 1935. It controls monetary policy, issues currency, and regulates banks.', subject: 'Economics', difficulty: 'easy' },
  { id: 'ca-a5', question: 'Which financial statement shows the financial position of a business at a point in time?', options: ['Profit & Loss Account', 'Balance Sheet', 'Cash Flow Statement', 'Trial Balance'], answer: 1, explanation: 'Balance Sheet shows assets, liabilities, and equity at a specific date. P&L shows performance over a period. Cash Flow shows cash movements.', subject: 'Accounting', difficulty: 'easy' },
];

